INSERT INTO `free_courses` (`id`, `title`, `description`, `course_image`, `url`, `created_at`, `updated_at`) VALUES
(7,	'GRATISKURS MOT SKRIVESPERRE',	'Hva gjør du når skriveprosessen stopper opp? Hvordan få bukt med indre kritiker, som kan sabotere et hvert godt manus? Hva gjør du når du ikke finner den røde tråden blant tekstsnuttene? Og hvordan bygge motivasjon når du ikke vet om dette vil bli til noe? Ikke fortvil, dette gratiskurset lærer deg å hoppe bukk over skrivesperren!',	'/storage/free-course-images/1501682022.jpeg',	'http://skrivesperre.no/',	'2017-08-02 06:45:26',	'2017-08-08 07:51:34'),
(8,	'GRATIS BARNEBOKKURS',	'Vil du gi barna den uforglemmelige leseropplevelsen du selv hadde som liten? Vi gir deg en innføring i det viktigste du må vite når du skal skrive for barn, blant annet: En tydelig hovedperson som barna kan identifisere seg med, et miljø de kan relatere seg til og språk og form som er tilpasset aldersgruppen.',	'/storage/free-course-images/1501682009.jpeg',	'http://www.skriveforbarn.no/',	'2017-08-02 06:45:47',	'2017-08-02 21:24:09'),
(9,	'GRATIS KRIMKURS',	'Gjennom et gratis minikurs i tre deler lærer vi deg det viktigste du trenger for å skrive god krim: Finne den perfekte forbrytelse, bygge fengslende og troverdige karakterer, plotte, legge ut spor, holde spenningen oppe og gi en logisk og overraskende løsning.\r\nEt must for alle som vil skrive Den Store Krimboken!',	'/storage/free-course-images/1502211146.jpeg',	'http://www.krimkurs.no',	'2017-08-02 06:46:04',	'2017-08-30 19:54:02'),
(10,	'GRATIS \"FINN DEN RØDE TRÅDEN\"-KURS',	'Sitter du med en haug av tekstsnutter og sliter med å finne den røde tråden? Lurer du på hva som er essensen i manuset, og hva som skal ut? Er du usikker på hva du egentlig har skrevet om? Ta vårt skrivekurs i tre deler om å finne den røde tråden, så får du hjelp til å definere prosjektet og sy sammen dokumentene.',	'/storage/free-course-images/1502180509.jpeg',	'http://dittkurs.no/',	'2017-08-08 08:17:39',	'2017-08-08 08:36:10'),
(11,	'GRATISKURS OM Å BOOSTE SKRIVESELVTILLITEN',	'Et godt manus er skrevet med autoritet, og leder leseren gjennom historien på en god og troverdig måte. For å skrive med autoritet trenger du selvtillit. Hvordan oppnår du det? Vi har laget et minikurs om å styrke skriveselvtilliten, med terapeutiske råd og tips for å du lure de små grå.',	'/storage/free-course-images/1502181304.jpeg',	'http://forfatterhjelp.no/',	'2017-08-08 08:35:04',	'2017-08-10 14:09:42'),
(12,	'GRATISKURS OM Å STYRKE SKRIVEDISIPLINEN',	'Klarer du ikke å disiplinere deg til å skrive? Ta vårt skrivekurs i tre deler om å skape en ny vane, lure deg selv til disiplin og slå knockout på den indre kritikeren (som kan ødelegge et hvert godt manus). Et må ha-kurs for deg som vil komme i mål med skriveprosjektet en gang for alle!',	'/storage/free-course-images/1502374118.jpeg',	'http://www.dinbestefortelling.no',	'2017-08-10 14:08:38',	'2017-08-30 19:53:48');
