INSERT INTO `lessons` (`id`, `course_id`, `title`, `content`, `delay`, `period`, `order`, `created_at`, `updated_at`) VALUES
(15,	7,	'STEG 1. Definer historien, skap karakterene og tilpass språket',	'<h2>\r\n    Del 1\r\n</h2>\r\n<h2>\r\n    Velkommen til ditt første steg på barnebokveien!\r\n</h2>\r\n<p>\r\n    \r\n</p>\r\n<iframe allowfullscreen=\"true\" frameborder=\"0\" height=\"300\" src=\"http://fast.wistia.net/embed/iframe/myjqklclr3?embedType=legacy_api&videoFoam=true&videoWidth=720?embedType=legacy_api&videoFoam=true&videoWidth=720&chromeless=false&controlsVisibleOnLoad=true&playbar=true&fullscreenButton=true&playerColor=ff0000\" width=\"400\"></iframe>\r\n<p>\r\n    \r\n</p>\r\n<h2>\r\n    ---\r\n</h2>\r\n<p>\r\n    \r\n</p>\r\n<iframe allowfullscreen=\"true\" frameborder=\"0\" height=\"300\" src=\"http://fast.wistia.net/embed/iframe/se7ss3gdm8?embedType=legacy_api&videoFoam=true&videoWidth=720?embedType=legacy_api&videoFoam=true&videoWidth=720&chromeless=false&controlsVisibleOnLoad=true&playbar=true&fullscreenButton=true&playerColor=ff0000\" width=\"400\"></iframe>\r\n<p>\r\n    \r\n</p>\r\n<p>\r\n    <b>HVA HANDLER HISTORIEN DIN OM?</b>\r\n</p>\r\n<p>\r\n    Hva handler fortellingen din om? Hva er essensen? Forsøk å oppsummere den i noen få, enkle setninger.<br><br>Bevissthet rundt din egen historie hjelper deg med å holde retningen og bli kvitt overflødige scener og karakterer underveis. Disse setningene er også viktige når du skal presentere manuset ditt for et forlag og senere promotere boka ut til lesere og media.<br><br><b>Obs!</b> Jo mindre barn du skriver for, jo viktigere er det at det er minst mulig delhistorier, overflødige karakterer og annet som virker forstyrrende og forvirrende. En femåring vil for eksempel ha vanskelig for å følge med på flere historier på en gang, holde styr på mange (og mangesidige) karakterer og forstå et komplisert plott. En tolvåring derimot, kan synes det er spennende med parallelle historier og nyanserte karakterer - og har ingen problemer med å henge med i mer intrikate plott.\r\n</p>\r\n<p>\r\n    <b>Dette skal du gjøre: </b>Tenk deg at du skal fortelle et barn hva historien din handler om. Si det gjerne høyt: Historien min handler omINSERT INTO `manuscripts` (`id`, `coursetaken_id`, `filename`, `word_count`, `grade`, `feedback_user_id`, `created_at`, `updated_at`) VALUES
