INSERT INTO `settings` (`id`, `setting_name`, `setting_value`) VALUES
(2,	'welcome_email',	'Hei og velkommen til Forfatterskolen!\r\n\r\nVi er så glade for å ha deg med! Vi i Forfatterskolen er selv forfattere, og håper at vi gjennom våre skrivekurs og erfaringer kan bli den redaktøren, mentoren og heiagjengen som hjelper deg med å lykkes med din skrivedrøm ? uansett nivå og sjanger. \r\n\r\nLykke til med skrivingen og husk at du når som helst kan ta kontakt hvis du trenger noe fra oss! \r\n\r\nAlt godt,\r\nKristine');
INSERT INTO `shop_manuscript_comments` (`id`, `shop_manuscript_taken_id`, `user_id`, `comment`, `created_at`, `updated_at`) VALUES
(1,	42,	2,	'test',	'2017-08-30 06:54:13',	'2017-08-30 06:54:13'),
(2,	42,	10,	'Lorem',	'2017-08-30 06:55:23',	'2017-08-30 06:55:23'),
(3,	49,	1,	'Fortellingen er basert på hendelser som foregikk i 1964. Totto, en gutt på 12 år, får plutselig livet snudd opp ned. Den ene dagen scorer han vinnermålet for Vormedal FK, den neste dagen kommer han inn på Haugesund Sykehus med en alvorlig diagnose. Derfra blir han sendt til Radiumhospitalet hvor han skrives inn som pasient nr. 27. Han blir snart plassert i  «dødsbunken» til professor Poppe. Faren Otto kjemper mot dødsprognosen, og allierer seg med  dr. Lorenz Nitter og med andre «dissentere» for å redde sønnen. Det blir en intens kamp både mot faglige autoriteter, mot tiden og mot sykdommen. Otto må mobilisere alt han har av mot,  standhaftighet og kjærlighet til sønnen for å redde ham. Dette er også en historie om hvordan en høysensitiv gutt opplever møtet med sykehusvesenet i en tid hvor ingenting var spesielt tilrettelagt for barn.  Jeg har ikke gitt ut bøker før, og selv om jeg er en godt voksen person, har jeg mye å lære i forhold til det rent håndverksmessige.  Tidligere versjoner av manuset er lest av manuskonsulenter, og jeg har prøvd å innarbeide tips fra dem i dette. Jeg har med rette eller urette ambisjoner om å få manuset utgitt på forlag, men er ikke fremmed for å publisere selv. Aller først vil jeg uansett ha en sjekk av manuset, i den foreliggende versjon, fra kompetent hold',	'2017-08-30 15:09:49',	'2017-08-30 15:09:49');
