(73,	17,	'Repriser Mars 17',	'<h1>\r\n    Redigeringswebinar 29.03\r\n</h1>\r\n<iframe allowfullscreen=\"true\" frameborder=\"0\" height=\"300\" src=\"http://fast.wistia.net/embed/iframe/osjjvcde2h?embedType=async&amp;videoFoam=true&amp;videoWidth=640?embedType=legacy_api&amp;videoFoam=true&amp;videoWidth=720&amp;chromeless=false&amp;controlsVisibleOnLoad=true&amp;playbar=true&amp;fullscreenButton=true&amp;playerColor=ff0000\" width=\"400\"></iframe>\r\n<h1>\r\n    Hvordan skrive fengende sakprosa - med Kjersti Wold 27.03.17\r\n</h1>\r\n<iframe allowfullscreen=\"true\" frameborder=\"0\" height=\"300\" src=\"http://fast.wistia.net/embed/iframe/a9wcahm1hd?embedType=async&amp;videoFoam=true&amp;videoWidth=720?embedType=legacy_api&amp;videoFoam=true&amp;videoWidth=720&amp;chromeless=false&amp;controlsVisibleOnLoad=true&amp;playbar=true&amp;fullscreenButton=true&amp;playerColor=ff0000\" width=\"400\"></iframe>\r\n<h1>\r\n    Redigeringswebinar 23.03.17\r\n</h1>\r\n<iframe allowfullscreen=\"true\" frameborder=\"0\" height=\"300\" src=\"http://fast.wistia.net/embed/iframe/z5xmzisj2h?embedType=async&amp;videoFoam=true&amp;videoWidth=720?embedType=legacy_api&amp;videoFoam=true&amp;videoWidth=720&amp;chromeless=false&amp;controlsVisibleOnLoad=true&amp;playbar=true&amp;fullscreenButton=true&amp;playerColor=ff0000\" width=\"400\"></iframe>\r\n<h1>\r\n    Alexander Sandtorv - Hvordan min bok ble antatt 13.03.17\r\n</h1>\r\n<iframe allowfullscreen=\"true\" frameborder=\"0\" height=\"300\" src=\"http://fast.wistia.net/embed/iframe/kibnqzmn5i?embedType=async&amp;videoFoam=true&amp;videoWidth=720?embedType=legacy_api&amp;videoFoam=true&amp;videoWidth=720&amp;chromeless=false&amp;controlsVisibleOnLoad=true&amp;playbar=true&amp;fullscreenButton=true&amp;playerColor=ff0000\" width=\"400\"></iframe>\r\n<h1>\r\n    Tone Johnsen lærer oss dramaturgi 06.03.17\r\n</h1>\r\n<iframe allowfullscreen=\"true\" frameborder=\"0\" height=\"300\" src=\"http://fast.wistia.net/embed/iframe/94momkcezo?e